const (
	banRole = "admin"
	kickRole = "mod"
)

var upgrader = websocket.Upgrader{
	ReadBufferSize:  1024,
	WriteBufferSize: 1024,
}

type Client struct {
	conn   *websocket.Conn
	role   string
	send   chan []byte
	server *Server
}

func (c *Client) readPump() {
	defer c.conn.Close()
	for {
		_, message, err := c.conn.ReadMessage()
		if err != nil {
			break
		}
		c.server.handleCommand(c, string(message))
	}
}

func (c *Client) writePump() {
	defer func() {
		c.conn.Close()
	}()
	for message := range c.send {
		err := c.conn.WriteMessage(websocket.TextMessage, message)
		if err != nil {
			break
		}
	}
}

type Server struct {
	router   http.Handler
	upgrader websocket.Upgrader
	clients  map[*Client]bool
	broadcast chan []byte
}

func (s *Server) handleCommand(client *Client, command string) {
	parts := strings.Fields(command)
	if len(parts) < 2 {
		return
	}
	cmd, args := parts[0], parts[1:]

	switch cmd {
	case "/kick":
		if client.role == banRole {
			client.server.kickUser(args[0])
		}
	case "/ban":
		if client.role == banRole {
			client.server.banUser(args[0])
		}
	case "/giveitems":
		if client.role == kickRole {
			client.server.giveItems(client, args...)
		}
	}
}

func (s *Server) broadcastMessage(msg []byte) {
	for client := range s.clients {
		client.send <- msg
	}
}

